import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  name: string;
  price: number;
  oldPrice?: number;
  category: string;
  image: string;
  rating: number;
  reviewsCount: number;
  sellerId: string;
  wilaya: string;
  isVerified: boolean;
  hasStudentDiscount: boolean;
  isFastDelivery: boolean;
  description: string;
}

export interface User {
  id: string;
  name: string;
  role: 'buyer' | 'seller';
  phone: string;
  avatar: string;
  isStudent?: boolean;
}

export interface ChatMessage {
  id: string;
  senderId: string;
  text: string;
  timestamp: Date;
}

export interface SalesData {
  month: string;
  sales: number;
  orders: number;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAIPromotions = async (productName: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `بصفتك خبيراً في التسويق في الجزائر، اقترح 3 جمل تسويقية جذابة للمنتج التالي: 
      الاسم: ${productName}
      الوصف: ${description}
      اجعلها باللهجة الجزائرية البيضاء المفهومة.`,
    });
    return response.text;
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "عرض خاص لفترة محدودة!";
  }
};

export const chatWithAI = async (message: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: message,
      config: {
        systemInstruction: "أنت مساعد ذكي لمنصة 'تجريلي' (Tajerly) للتجارة الإلكترونية في الجزائر. ساعد المستخدمين في العثور على أفضل الصفقات، وتقديم معلومات عن التوصيل للولايات 58. كن ودوداً واستخدم كلمات جزائرية مثل 'خويا/ختي'، 'بصحتك'، 'واش راك حاب' إذا لزم الأمر.",
      }
    });
    return response.text;
  } catch (error) {
    return "عذراً، واجهت مشكلة في الاتصال بمساعد الذكاء الاصطناعي.";
  }
};

import React, { useState, useEffect } from 'react';
