            {/* Quick Filters */}
            <div className="flex flex-wrap items-center gap-3 mb-8 overflow-x-auto pb-2 scrollbar-hide">
              <button 
                onClick={() => setSelectedCategory('all')}
                className={`px-6 py-2 rounded-full font-medium transition-all whitespace-nowrap ${selectedCategory === 'all' ? 'bg-tajerly-green text-white shadow-md' : 'bg-white text-gray-600 hover:bg-gray-100 border'}`}
              >
