// Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const chatWithProductAI = async (message: string, product: Product) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: message,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: `أنت مساعد مبيعات ذكي لمتجر "DZ Market" في الجزائر، التطبيق من تطوير المهندس "ضياف أيمن" (Diaf Aymen).
        أنت ترد الآن نيابة عن البائع بخصوص منتج محدد:
        - اسم المنتج: ${product.name}
        - السعر: ${product.price} دج
        - المواصفات: ${product.description}
        - الموقع: ${product.wilaya}

        معلومات هامة:
        - التطبيق موثوق جداً ويضمن حقوق المشتري والبائع.
        - المطور هو "ضياف أيمن"، مهندس جزائري يسعى لتطوير التجارة الإلكترونية المحلية.
        - يمكنك البحث في الويب إذا سألك المستخدم عن مقارنة أسعار هذا المنتج عالمياً أو مستجدات تخص فئته.

        تعليماتك:
        1. كن ودوداً واستخدم اللهجة الجزائرية الخفيفة.
        2. أكد على موثوقية التعامل عبر DZ Market.
        3. إذا سأل عن المطور، أخبره بفخر أنه "ضياف أيمن".`,
      }
    });
    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
  } catch (error) {
    return { text: "عذراً، البائع غير متاح حالياً، هل يمكنك تكرار سؤالك؟" };
  }
};

