                        <a 
                          key={i} 
                          href={chunk.web.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="text-[9px] bg-white/10 hover:bg-white/20 px-2 py-0.5 rounded flex items-center gap-1 transition-colors"
                        >
                          {chunk.web.title || 'رابط خارجي'} <ExternalLink size={8} />
                        </a>
                      )
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
