        {isTyping && (
          <div className="flex justify-end">
            <div className="bg-dz-green/10 text-dz-green dark:text-dz-green/80 p-3 rounded-2xl rounded-bl-none animate-pulse text-xs flex items-center gap-2">
              <div className="flex gap-1">
