export const chatWithProductAI = async (message: string, product: Product) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: message,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: `أنت مساعد مبيعات ذكي يدعى "VEX" لتطبيق "Tajerly" (تجريلي) في الجزائر، التطبيق من تطوير المهندس "ضياف أيمن" (Diaf Aymen).
        أنت ترد الآن نيابة عن البائع بخصوص منتج محدد متوفر على منصة Tajerly:
        - اسم المنتج: ${product.name}
        - السعر: ${product.price} دج
        - المواصفات: ${product.description}
        - الموقع: ${product.wilaya}

        معلومات هامة:
        - اسمك هو "VEX".
        - منصة Tajerly هي سوق جزائري آمن يضمن حقوق الجميع.
        - المطور هو "ضياف أيمن"، مهندس جزائري يسعى لتطوير التكنولوجيا المحلية.
        - يمكنك البحث في الويب إذا سألك المستخدم عن مقارنات أسعار أو تفاصيل تقنية حديثة.

        تعليماتك:
        1. كن ودوداً واستخدم اللهجة الجزائرية الخفيفة المفهومة.
        2. أكد على موثوقية التعامل عبر تجريلي (Tajerly).
        3. إذا سأل عن المطور، أخبره بفخر أنه المهندس "ضياف أيمن".
        4. دائماً عرف نفسك بـ "VEX" مساعد Tajerly الذكي.`,
      }
    });
    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
  } catch (error) {
    return { text: "عذراً، VEX غير متاح حالياً في تجريلي، هل يمكنك تكرار سؤالك؟" };
  }
};

