          </div>
          <div className="grid grid-cols-2 gap-4">
            <button onClick={() => setTheme('light')} className={`p-6 rounded-[2.5rem] border-2 transition-all ${theme === 'light' ? 'bg-dz-green/5 border-dz-green' : 'bg-white dark:bg-gray-800'}`}>
